// FIX H3: Calcular pagos pendientes con idempotencia por periodo.
// La clave de idempotencia previene doble pago en reintentos.
const now = new Date();
const creators = $input.all().map(i => i.json);

// Determinar periodo actual (quincena)
const day = now.getDate();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const period_start = day <= 15 
  ? `${year}-${month}-01` 
  : `${year}-${month}-16`;
const period_end = day <= 15 
  ? `${year}-${month}-15` 
  : new Date(year, now.getMonth() + 1, 0).toISOString().split('T')[0];

console.log(`[payment-scheduler] Periodo: ${period_start} → ${period_end}. Creators activos: ${creators.length}`);

// Para cada creator calcular idempotency_key del periodo
const paymentsToProcess = creators.map(creator => {
  // FIX H3: Idempotency key unica por creator+periodo — evita doble pago en reintentos
  const idempotency_key = `${creator.id}|${period_start}|${period_end}`;
  return {
    ...creator,
    period_start,
    period_end,
    idempotency_key
  };
});

return paymentsToProcess.map(p => ({ json: p }));

// Calcular monto total pendiente para este creator en el periodo
// En produccion esto deberia venir de una query SQL con JOIN a content_pieces
// Por ahora usamos el campo rate_usd del creator como aproximacion
const creator = $('Split In Batches').item.json;

// Verificar que hay monto a pagar (threshold minimo USD 20)
const total_usd = creator.pending_amount_usd || 0;
if (total_usd < 20) {
  return [{ json: { _skip: true, reason: `Amount below threshold: $${total_usd}`, creator_id: creator.id } }];
}

return [{ json: {
  creator_id: creator.id,
  creator_name: creator.full_name,
  creator_email: creator.email,
  total_usd: total_usd,
  period_start: creator.period_start,
  period_end: creator.period_end,
  idempotency_key: creator.idempotency_key,
  provider: total_usd > 500 ? 'mercury' : 'wise'
} }];

