// FIX H3: Verificar que el banco acepto el pago antes de marcar como submitted.
const bankResponse = $input.first().json;
const paymentRecord = $('Supabase - Create Payment Record (initiating)').item.json;
const provider = $('Code - Calculate Payment Amount').item.json.provider;

// Verificar respuesta del banco
if (provider === 'mercury') {
  // Mercury: esperar 201 con id de transaccion
  if (!bankResponse.id) {
    throw new Error(`[payment] Mercury no retorno ID de transaccion. Response: ${JSON.stringify(bankResponse).slice(0, 500)}`);
  }
  return [{ json: {
    payment_db_id: paymentRecord.id,
    provider_tx_id: bankResponse.id,
    status: 'submitted',
    creator_id: $('Code - Calculate Payment Amount').item.json.creator_id,
    total_usd: $('Code - Calculate Payment Amount').item.json.total_usd,
    provider: 'mercury'
  } }];
} else {
  // Wise: esperar id de transfer
  if (!bankResponse.id) {
    throw new Error(`[payment] Wise no retorno ID de transfer. Response: ${JSON.stringify(bankResponse).slice(0, 500)}`);
  }
  return [{ json: {
    payment_db_id: paymentRecord.id,
    provider_tx_id: String(bankResponse.id),
    status: 'submitted',
    creator_id: $('Code - Calculate Payment Amount').item.json.creator_id,
    total_usd: $('Code - Calculate Payment Amount').item.json.total_usd,
    provider: 'wise'
  } }];
}

